const images = $input.first().json._images || [];
const items = [];
for (let i = 0; i < images.length; i++) {
  const img = images[i];
  if (img.startsWith('data:')) {
    const match = img.match(/data:([^;]+);base64,(.+)/);
    if (match) {
      items.push({
        json: { index: i, type: 'base64', mime: match[1] },
        binary: { data: { data: match[2], mimeType: match[1] } }
      });
    }
  } else if (img.startsWith('http')) {
    items.push({ json: { index: i, type: 'url', url: img } });
  }
}
return items;

const items = $input.all();
const urls = [];
for (let i = 0; i < items.length; i++) {
  const json = items[i].json;
  if (json.secure_url) {
    urls.push({ index: json.index != null ? json.index : i, url: json.secure_url });
  } else if (json.url) {
    urls.push({ index: json.index != null ? json.index : i, url: json.url });
  }
}
return urls.map(u => ({ json: u }));

