const posterPrompt = $input.first().json.output || "";
const imageItems = $items("提取URL");
const refImages = [];
for (const item of imageItems) {
  if (item.json.url) refImages.push({ url: item.json.url });
}
const body = {
  model: "seedream-5-0-260128",
  prompt: posterPrompt,
  size: "1792x1024",
  response_format: "url"
};
if (refImages.length) body.reference_images = refImages;
return { json: body };

const resp = $input.first().json;
// Volcengine images/generations format: { data: [{ url: '...' }] }
if (resp.data && Array.isArray(resp.data) && resp.data[0]?.url) {
  return { json: { keyframeUrl: resp.data[0].url } };
}
// Fallback: OpenAI chat completions format
const content = resp.choices?.[0]?.message?.content;
if (content) {
  const urlMatch = content.match(/!\[image\]\((https?:\/\/[^)]+)\)/);
  if (urlMatch) return { json: { keyframeUrl: urlMatch[1] } };
  const b64Match = content.match(/data:image\/(\w+);base64,([^)\s]+)/);
  if (b64Match) {
    return { json: { keyframeMime: 'image/' + b64Match[1] },
      binary: { data: { data: b64Match[2], mimeType: 'image/' + b64Match[1] } } };
  }
}
throw new Error('Could not extract image from response: ' + JSON.stringify(resp).slice(0, 500));

// Derive Seedance segments from storyboard + total duration
const storyboard = $('解析全局分镜').first().json;
const totalDuration = storyboard.totalDuration || 15;
const shots = storyboard.storyboards || [];

let segments = [];

if (totalDuration <= 15) {
  // 15s = 1 segment, no extension
  segments = [{
    segment_id: 1,
    duration: 15,
    is_extension: false,
    shots_covered: shots.map(s => s.scene_id),
    shot_types: shots.map(s => s.shot_type),
    visual_summary: shots.map(s => '[Shot ' + s.scene_id + ': ' + s.shot_type + '] ' + s.visual_description_cn).join(' | '),
    camera_movement: shots[0].camera_movement || 'slow_push_in',
    storyboard_shots: shots
  }];
} else {
  // 25s = 15s base + 10s extension
  const mid = Math.ceil(shots.length / 2);
  segments = [
    {
      segment_id: 1, duration: 15, is_extension: false,
      shots_covered: shots.slice(0, mid).map(s => s.scene_id),
      shot_types: shots.slice(0, mid).map(s => s.shot_type),
      visual_summary: shots.slice(0, mid).map(s => '[Shot ' + s.scene_id + ': ' + s.shot_type + '] ' + s.visual_description_cn).join(' | '),
      camera_movement: shots[0].camera_movement || 'slow_push_in',
      storyboard_shots: shots.slice(0, mid)
    },
    {
      segment_id: 2, duration: 10, is_extension: true,
      shots_covered: shots.slice(mid).map(s => s.scene_id),
      shot_types: shots.slice(mid).map(s => s.shot_type),
      visual_summary: shots.slice(mid).map(s => '[Shot ' + s.scene_id + ': ' + s.shot_type + '] ' + s.visual_description_cn).join(' | '),
      camera_movement: shots.slice(mid)[0]?.camera_movement || 'slow_orbit',
      storyboard_shots: shots.slice(mid)
    }
  ];
}

return segments.map(seg => ({
  json: {
    ...storyboard,
    ...seg,
    totalSegments: segments.length
  }
}));

