const output = $input.first().json.output;
let parsed;
try { parsed = JSON.parse(output); } catch {
  const m = output.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) parsed = JSON.parse(m[1]);
  else { const o = output.match(/\{[\s\S]*\}/); if (o) parsed = JSON.parse(o[0]); }
}
if (!parsed || !parsed.videoPrompt) throw new Error('Failed to parse videoPrompt');
return { json: { ...parsed, segment_id: $('Loop Over Seedance Segments').item.json.segment_id, is_extension: $('Loop Over Seedance Segments').item.json.is_extension, duration: $('Loop Over Seedance Segments').item.json.duration } };

const videoPlan = $input.first().json;
const seg = $('Loop Over Seedance Segments').item.json;
const config = $('入参标准化').first().json._config;
const segmentId = seg.segment_id;
const totalSegs = $('Loop Over Seedance Segments').item.json.totalSegments;
const isExtension = seg.is_extension;

// Build prompt: style lock prefix for extensions
let rawPrompt = videoPlan.videoPrompt || '时装lookbook镜头。缓慢推入、柔光摄影棚、纯白背景。4K、photorealistic。';
if (isExtension) {
  const styleLock = '风格锁定：与原始关键帧保持完全一致的视觉。相同模特外观、相同纯白摄影棚背景、相同柔和均匀光线、相同面料质感与服装细节品质。所有视觉参数锚定核心关键帧。';
  rawPrompt = styleLock + rawPrompt;
}
const prompt = String(rawPrompt).replace(/[\x00-\x1F\x7F]/g, ' ').trim().slice(0, 2000);
const duration = seg.duration || 15;

// Global style anchor: the core keyframe
const keyframeUrl = $('上传关键帧').first().json.secure_url || $('上传关键帧').first().json.url || $('提取关键帧').first().json.keyframeUrl || '';

// Previous video URL from last loop iteration
const prevVideoUrl = $json.prevVideoUrl || '';

const content = [{ type: 'text', text: prompt }];

if (!isExtension) {
  // Base segment: generate from keyframe
  content.push({ type: 'image_url', image_url: { url: keyframeUrl } });
} else if (prevVideoUrl) {
  // Extension: previous video for temporal continuity + keyframe as style anchor
  content.push({ type: 'video_url', video_url: { url: prevVideoUrl } });
  content.push({ type: 'image_url', image_url: { url: keyframeUrl } });
  content.push({ type: 'text', text: `基于上一段视频的无缝延长。第 ${segmentId} of ${totalSegs}. 原始关键帧作为全局风格锚点。保持视觉一致性：相同模特外观、相同光线、相同纯白背景。自动生成2-3秒无缝过渡。` });
}

const requestBody = {
  model: config['seedance_model'] || 'doubao-seedance-2.0-fast',
  content,
  size: '720p',
  ratio: '16:9',
  duration,
  fps: config['seedance_fps'] || 24,
  motion_strength: config['seedance_motion'] || 1.5,
  seed: config['seedance_seed'] || 42
};

return { json: { videoPrompt: prompt, keyframeUrl, prevVideoUrl, duration, segment_id: segmentId, totalSegments: totalSegs, is_extension: isExtension, body: requestBody } };

const resp = $input.first().json;
const id = resp.id || resp.task_id || resp.data?.task_id || '';
if (!id) throw new Error('No task ID in response');
return { json: { task_id: id, segment_id: $('Loop Over Seedance Segments').item.json.segment_id, _retryCount: 0, prevVideoUrl: $json.prevVideoUrl || '' } };

const resp = $input.first().json;
const url = resp.video_url || resp.output?.video_url || resp.result?.video_url || resp.data?.video_url || resp.content?.video_url || '';
const status = resp.status || resp.data?.status || '';
if (status !== 'succeeded' && status !== 'completed') throw new Error('Video not ready');
if (!url) throw new Error('No video URL in response');
const sceneId = $json.scene_id ?? $('Loop Over Seedance Segments').item.json.segment_id;
return { json: { video_url: url, scene_id: sceneId, status, prevVideoUrl: url } };

const input = $input.first();
const seg = $('Loop Over Seedance Segments').item.json;
const segmentId = seg.segment_id;
const totalSegs = seg.totalSegments || $('Loop Over Seedance Segments').item.json.totalSegments;
const videoUrl = input.json.video_url || input.json.prevVideoUrl || '';
return { json: { segment_id: segmentId, video_url: videoUrl, prevVideoUrl: videoUrl, completed: true, isLast: segmentId >= totalSegs } };
